import React, { useState, useRef, useEffect } from 'react';

const buttonGrid = [
  ['7', '8', '9', '/'],
  ['4', '5', '6', '*'],
  ['1', '2', '3', '-'],
  ['0', '.', '=', '+']
];

const operatorSet = new Set(['/', '*', '-', '+']);

export default function Calculator() {
  const [input, setInput] = useState('');
  const [history, setHistory] = useState([]);
  const [error, setError] = useState('');
  const inputRef = useRef(null);

  // Focus input on mount
  useEffect(() => {
    inputRef.current && inputRef.current.focus();
  }, []);

  // Keyboard support
  useEffect(() => {
    function handleKey(e) {
      if (e.key === 'Enter') {
        e.preventDefault();
        handleEqual();
      } else if ((e.key >= '0' && e.key <= '9') || operatorSet.has(e.key) || e.key === '.' ) {
        handleInput(e.key);
      } else if (e.key === 'Backspace') {
        setInput(prev => prev.slice(0, -1));
        setError('');
      }
    }
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  });

  const handleInput = (val) => {
    setError('');
    // Prevent multiple operators in a row
    if (operatorSet.has(val)) {
      if (input === '' || operatorSet.has(input.slice(-1))) return;
    }
    // Prevent multiple decimals in a number
    if (val === '.') {
      const parts = input.split(/[-+*/]/);
      if (parts[parts.length-1].includes('.')) return;
      if (input === '' || operatorSet.has(input.slice(-1))) {
        setInput(prev => prev + '0.');
        return;
      }
    }
    setInput(prev => prev + val);
  };

  const handleEqual = () => {
    if (!input || operatorSet.has(input.slice(-1))) {
      setError('Expresión inválida');
      return;
    }
    try {
      // eslint-disable-next-line no-eval
      const result = eval(input).toString();
      setHistory(prev => [
        { expr: input, result },
        ...prev.slice(0, 9)
      ]);
      setInput(result);
      setError('');
    } catch {
      setError('Error de cálculo');
    }
  };

  const handleClear = () => {
    setInput('');
    setError('');
  };

  const handleHistoryClick = (expr) => {
    setInput(expr);
    setError('');
    inputRef.current && inputRef.current.focus();
  };

  // Styles
  const colors = {
    bg: '#f6f8fb',
    panel: '#fff',
    accent: '#667eea',
    accent2: '#764ba2',
    error: '#e53e3e',
    border: '#e2e8f0',
    text: '#23272f',
    op: '#4fd1c5',
    histBg: '#f1f5fa',
    histSel: '#e0e7ff',
  };
  const style = {
    container: {
      minHeight: '100vh',
      background: `linear-gradient(135deg, ${colors.accent} 0%, ${colors.accent2} 100%)`,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: '-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif',
      padding: 16,
    },
    calcPanel: {
      background: colors.panel,
      borderRadius: 18,
      boxShadow: '0 4px 24px rgba(60,60,120,0.12)',
      padding: 28,
      width: 340,
      maxWidth: '100vw',
      display: 'flex',
      flexDirection: 'column',
      gap: 18,
    },
    display: {
      background: '#f1f5fa',
      borderRadius: 12,
      minHeight: 56,
      display: 'flex',
      alignItems: 'flex-end',
      justifyContent: 'flex-end',
      fontSize: 28,
      fontWeight: 600,
      color: colors.text,
      padding: '12px 16px 8px 16px',
      letterSpacing: 1,
      wordBreak: 'break-all',
      border: `1.5px solid ${colors.border}`,
      transition: 'box-shadow 0.2s',
      outline: error ? `2px solid ${colors.error}` : 'none',
    },
    error: {
      color: colors.error,
      fontSize: 14,
      minHeight: 18,
      marginTop: -6,
      marginBottom: 2,
      textAlign: 'right',
    },
    buttonGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(4, 1fr)',
      gap: 10,
      marginTop: 6,
    },
    btn: {
      background: colors.bg,
      border: `1.5px solid ${colors.border}`,
      borderRadius: 10,
      fontSize: 22,
      fontWeight: 500,
      padding: '14px 0',
      color: colors.text,
      cursor: 'pointer',
      transition: 'background 0.2s, box-shadow 0.2s, color 0.2s',
      outline: 'none',
      boxShadow: '0 1px 2px rgba(60,60,120,0.04)',
    },
    btnOp: {
      color: colors.accent2,
      background: '#e9e7fa',
      fontWeight: 700,
    },
    btnEq: {
      background: `linear-gradient(90deg, ${colors.accent} 60%, ${colors.accent2} 100%)`,
      color: '#fff',
      fontWeight: 700,
      boxShadow: '0 2px 8px rgba(118,75,162,0.08)',
    },
    btnHover: {
      background: '#e0e7ff',
    },
    btnActive: {
      background: '#c7d2fe',
    },
    clearBtn: {
      background: colors.error,
      color: '#fff',
      border: 'none',
      borderRadius: 10,
      fontWeight: 700,
      fontSize: 16,
      padding: '10px 0',
      marginBottom: 2,
      cursor: 'pointer',
      transition: 'background 0.2s',
      boxShadow: '0 1px 4px rgba(229,62,62,0.07)',
    },
    historyPanel: {
      background: colors.histBg,
      borderRadius: 12,
      padding: 12,
      marginTop: 12,
      minHeight: 60,
      maxHeight: 180,
      overflowY: 'auto',
      fontSize: 15,
      boxShadow: '0 2px 8px rgba(102,126,234,0.06)',
    },
    histItem: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      padding: '7px 0',
      borderBottom: `1px solid ${colors.border}`,
      cursor: 'pointer',
      transition: 'background 0.18s',
    },
    histItemLast: {
      borderBottom: 'none',
    },
    histExpr: {
      color: colors.text,
      fontWeight: 500,
      marginRight: 8,
    },
    histResult: {
      color: colors.accent2,
      fontWeight: 700,
    },
    histItemHover: {
      background: colors.histSel,
    },
    mobile: {
      width: '100vw',
      minWidth: 0,
      maxWidth: 420,
      padding: 10,
    }
  };

  // Responsive tweak
  const [isMobile, setIsMobile] = useState(false);
  useEffect(() => {
    const onResize = () => setIsMobile(window.innerWidth < 430);
    onResize();
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  // Button hover/active
  const [hoverBtn, setHoverBtn] = useState(null);
  const [activeBtn, setActiveBtn] = useState(null);

  // History hover
  const [hoverHist, setHoverHist] = useState(-1);

  return (
    <div style={style.container}>
      <div style={{...style.calcPanel, ...(isMobile ? style.mobile : {})}}>
        {/* Display */}
        <input
          ref={inputRef}
          style={style.display}
          value={input}
          readOnly
          tabIndex={-1}
          aria-label="Pantalla de la calculadora"
        />
        <div style={style.error}>{error}</div>
        {/* Clear */}
        <button
          style={{...style.clearBtn, background: error ? '#e53e3e' : colors.error, opacity: input ? 1 : 0.5}}
          onClick={handleClear}
          disabled={!input}
        >
          Limpiar
        </button>
        {/* Buttons */}
        <div style={style.buttonGrid}>
          {buttonGrid.flat().map((btn, i) => {
            let btnStyle = {...style.btn};
            if (operatorSet.has(btn)) btnStyle = {...btnStyle, ...style.btnOp};
            if (btn === '=') btnStyle = {...btnStyle, ...style.btnEq};
            if (hoverBtn === i) btnStyle = {...btnStyle, ...style.btnHover};
            if (activeBtn === i) btnStyle = {...btnStyle, ...style.btnActive};
            return (
              <button
                key={btn}
                style={btnStyle}
                onMouseEnter={() => setHoverBtn(i)}
                onMouseLeave={() => setHoverBtn(null)}
                onMouseDown={() => setActiveBtn(i)}
                onMouseUp={() => setActiveBtn(null)}
                onClick={() => {
                  if (btn === '=') handleEqual();
                  else handleInput(btn);
                }}
                tabIndex={0}
                aria-label={btn === '=' ? 'Igual' : btn}
              >
                {btn}
              </button>
            );
          })}
        </div>
        {/* History */}
        <div style={style.historyPanel}>
          <div style={{fontWeight:600, color:colors.accent2, marginBottom:6, fontSize:15}}>Historial</div>
          {history.length === 0 && (
            <div style={{color:'#b0b2ba', fontSize:14, padding:'8px 0'}}>Sin cálculos previos.</div>
          )}
          {history.map((h, idx) => (
            <div
              key={idx}
              style={{
                ...style.histItem,
                ...(idx === history.length-1 ? style.histItemLast : {}),
                ...(hoverHist === idx ? style.histItemHover : {})
              }}
              onMouseEnter={() => setHoverHist(idx)}
              onMouseLeave={() => setHoverHist(-1)}
              onClick={() => handleHistoryClick(h.expr)}
              tabIndex={0}
              aria-label={`Usar ${h.expr}`}
            >
              <span style={style.histExpr}>{h.expr}</span>
              <span style={style.histResult}>= {h.result}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
